-- A. CASTRO'S CUBA  (unit = 'P2-AUTH', category = '6. Cuba (Castro)')
-- ══════════════════════════════════════════════════════════════════════════

-- ── A1. New Checklist Items ───────────────────────────────────────────────
-- Existing section hist-p2-auth-cl-6 has 7 items. Add more detailed ones.
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can explain the conditions under Batista that led to Castro''s emergence', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can describe the Moncada Barracks attack (1953) and its significance', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can analyse Castro''s guerrilla campaign in the Sierra Maestra (1956-59)', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can explain the role of propaganda in Castro''s rise (Radio Rebelde, NYT interview)', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can discuss Castro''s consolidation of power 1959-65 (use of force, legal methods, charisma)', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can analyse the Bay of Pigs invasion and its impact on Castro''s position', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can explain the nature and treatment of opposition (Escambray, Matos, Morgan)', 14);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can evaluate the Special Period (1991-96) and its threat to Castro''s regime', 15);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can discuss Castro''s education policies with specific statistics', 16);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can evaluate Castro''s healthcare policies and their limitations', 17);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can analyse the impact of Castro''s policies on women (FCW, Family Code, literacy campaign)', 18);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can discuss the extent of authoritarian control achieved by Castro', 19);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-auth-cl-6', 'I can compare Castro''s Moncada Programme aims with Hitler''s 25 Points', 20);

-- ── A2. New Flashcards ───────────────────────────────────────────────────
-- Existing topic hist-p2-auth-fc-6 has 5 cards (sort_order 1-5). Continue from 6.

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Batista''s Regime', 'Fulgencio Batista ruled Cuba as a US-backed dictator. His regime was corrupt, authoritarian, and served US economic interests. Widespread poverty, inequality, and political repression created conditions for revolution.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Moncada Barracks Attack (26 July 1953)', 'Castro''s failed attack on the Moncada military barracks in Santiago. Most attackers died or were captured. Castro was tried and gave his famous "History Will Absolve Me" speech, gaining national prominence. Released in 1955 after international pressure.', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', '"History Will Absolve Me" Speech', 'Castro''s defence speech at his Moncada trial. He highlighted the illegal nature of Batista''s coup, outlined his programme (end corruption, land reform, literacy, healthcare, reduced US influence), and gained a national platform. International pressure led to his release in 1955.', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Granma Expedition (1956)', 'Castro and 82 revolutionaries sailed from Mexico on the yacht Granma to Cuba. They were met by Batista''s military and most died, with a few survivors (including Castro, Guevara) fleeing to the Sierra Maestra mountains to begin guerrilla warfare.', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Guerrilla Tactics in Sierra Maestra', 'Castro''s forces used classic guerrilla tactics: retreat when attacked, hit-and-run attacks, small autonomous groups, mobile forces, reliance on peasant support. They wore down Batista''s conventional army, which failed to use counterinsurgency tactics and instead relied on artillery and tanks (static targets).', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Sierra Maestra Campaign (1956-59)', '1956-57: Survival phase, developing peasant support, La Plata Garrison attack, El Uvero victory. Batista withdrew forces, ceding Sierra Maestra. Guerrillas established base at La Plata, ran Radio Rebelde (Cuba''s most popular station) and El Cubano Libre newspaper. Castro ate same portions as his troops, establishing charismatic leadership.', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Battle of Santa Clara (Dec 1958)', 'Che Guevara captured Santa Clara with a 300:4000 troop ratio, highlighting Fidelista military competence. This was the decisive battle; Batista fled on 31 December 1958, and Castro arrived in Havana on 8 January 1959 after travelling through Cuba. The rebel army never exceeded ~2000 men.', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Castro''s Propaganda Methods', 'Moncada trial gave national prominence. "History Will Absolve Me" speech. Granma expedition promise kept ("I will return by 1957"). El Cubano Libre newspaper. Radio Rebelde — most popular station in Cuba. Herbert Matthews NYT interview and ABC TV interview established international sympathy. Emphasised ending corruption.', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Consolidation of Power (1959-65)', 'The period 1959-65 saw Castro eliminate all external and internal opposition. Methods included: use of force (trials/executions of Batista supporters), legal methods (nationalisation, land reform), charismatic leadership, and propaganda dissemination. By 1965 there was no active opposition.', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Bay of Pigs Invasion (April 1961)', 'CIA-backed attempt by Cuban exiles to overthrow Castro. Failed miserably. Castro used it to highlight US interference and consolidate domestic support. Both Castro and the USSR concluded the US lacked intention to take significant direct action against Cuba.', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Escambray Rebellion', 'Anti-Communist rebels (wealthier peasants, middle class, farmers opposing expropriation, Batista loyalists) used guerrilla warfare in Escambray Mountains. CIA pulled out after Bay of Pigs failure. No outstanding leaders, outnumbered, no popular support. Castro used overwhelming resources to eradicate them — "comb the brush, elbow to elbow".', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Opposition Figures: Matos & Morgan', 'Hubert Matos: concerned about Communism entering revolutionary government, had supported Castro. William Alexander Morgan: supported Castro''s revolution until it turned Communist — he opposed Communism. Both were notable political figures/elites who were suppressed.', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Castro''s Foreign Policy', 'CIA ran several failed assassination attempts. Doctor Diplomacy: sending doctors to less-developed countries (particularly in Africa) improved relations and helped avoid consequences of the US embargo. Cold War alignment with Soviets (85% of trade). Cuba supported liberation movements internationally.', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'The Special Period (1991-96)', 'Collapse of USSR (1991) devastated Cuba — Soviets were 85% of trading partners, economy fell 40%. Severe hardship: bikes replaced cars (no fuel), power shortages. US passed Torricelli Act (1992) and Helms-Burton Act (1996) restricting trade. Castro''s power was most at risk during this period.', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Special Period Response', 'Cuba emphasised revolutionary ideology and sought new markets. Pragmatic policies: dollarisation of economy, encouraging private enterprise, inviting foreign firms (1995). By mid-1990s 50+ dissident groups emerged (first time since 1965). 100 members of Concilio Cubano arrested in 1996. By 1996 situation broadly improved. US flights to Cuba began in 1998.', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Moncada Programme Aims', 'Castro''s programme from "History Will Absolve Me": (1) End corruption, (2) Improved working conditions and profit-sharing, (3) Land and agrarian reform, (4) Reduced US influence and Cuban nationalism, (5) Increased literacy and improved healthcare, plus infrastructure/sewers.', 21);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Castro''s Education Policies', 'Largely successful. Teachers increased from 20,000 to 60,000 (pre-Revolution to 1963). 1961 literacy campaign raised literacy from 40% to 96% — highest in Latin America. Primary enrollment: 800,000 (1958-59) to 3.3M (1982-83). Secondary schools: 80 to 1,900. BUT: brain drain (teachers left 1959-61), high investment reduced funds for other areas, and education used for ideological indoctrination.', 22);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Castro''s Healthcare Policies', 'Made healthcare free for all. 1,100 doctors graduated annually. Eliminated polio through immunisation; Cuba declared malaria-free. Improved infant mortality and life expectancy. BUT: shortages through 1980s, US embargo restricted medicine access, initially undertrained staff, and gains did not survive the Special Period.', 23);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Population & Demographics Under Castro', 'Population grew from 5.8M (1953) to 8.5M (1970). Birth rates surged from 27/1000 (1958) to 37/1000 (1962). Marriage rates doubled 1958-61. BUT: increased birth/marriage rates did not translate to long term. Despite healthcare reform, emigration remained high and Cuba''s population is now shrinking.', 24);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Impact on Women in Cuba', 'Federation of Cuban Women (1960): expanded to 2.6M members. Women''s employment rose from 13% (1958) to 44% (2008). Women held 43% of parliament (2008). 1961 Literacy Campaign mobilised 100,000 women; 56% of newly literate were women. 1975 Family Code mandated egalitarian family law. BUT: largely ignored — women did 75% of domestic labour in 1990s. Cultural resistance (machismo). Special Period pushed women into sex work.', 25);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', '1975 Family Code', 'Aimed to dismantle patriarchal family structures. Required men to do half the chores. Provided maternity cover, abortions, day-care. Simplified divorce procedures. BUT largely ignored — 76% of women who entered the labour force in 1969 dropped out within a year. Tanay: "good intentions, but fundamentally useless".', 26);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Impact on Minorities', 'LGBTQ+ individuals were incarcerated for a period. Castro''s regime repressed homosexuality as "counter-revolutionary". This represents a significant failure in the regime''s social policies and contradicts claims of egalitarianism.', 27);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Pact of Caracas (1958)', 'All opposition groups agreed to end the Batista regime and restore democracy. Castro did not follow through on the democratic restoration promise after taking power, instead consolidating a one-party state.', 28);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Battle of La Plata (1958)', 'Part of Batista''s Verano Offensive — his last major attempt after US support ended. 2 battalions vs a smaller rebel force. Result: 3 rebel injuries vs ~250 Batista casualties. Demonstrated the competence of guerrilla forces against conventional military.', 29);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Castro''s Ideological Flexibility', '"Anything anti-communist is now also anti-revolutionary." Castro did not read Das Kapital before calling himself a Marxist-Leninist. Economic ideology was a matter of political convenience rather than heartfelt beliefs. Concerns that elections could be influenced by the United States justified one-party rule.', 30);

-- ── A3. New MCQ Questions ────────────────────────────────────────────────

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-300', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The Moncada Barracks attack took place in:', '1950', '1953', '1956', '1959', 1, 'The Moncada Barracks attack occurred on 26 July 1953. Though it failed militarily, it gave Castro national prominence through his trial and "History Will Absolve Me" speech.', 300);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-301', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Castro''s guerrilla forces in the Sierra Maestra never exceeded approximately:', '200 men', '2,000 men', '10,000 men', '50,000 men', 1, 'The rebel army never exceeded approximately 2,000 men (estimates range from 300 to 8,000 but 2,000 is the best estimate, according to Wolf). Despite this small size, they defeated Batista''s much larger conventional forces.', 301);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-302', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Which battle saw Che Guevara defeat forces at a 300:4000 ratio?', 'Battle of La Plata', 'Battle of Santa Clara', 'Battle of El Uvero', 'Battle of Havana', 1, 'On 31 December 1958, Che Guevara captured Santa Clara with a roughly 300:4000 troop ratio, demonstrating the competence of the Fidelistas. Batista fled Cuba the same day.', 302);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-303', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The Bay of Pigs invasion occurred in:', 'January 1959', 'April 1961', 'October 1962', 'March 1960', 1, 'The CIA-backed Bay of Pigs invasion took place in April 1961 and failed miserably. Castro used it to highlight US interference and consolidate domestic support.', 303);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-304', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'What percentage of Cuba''s trade was with the Soviet Union before 1991?', '50%', '65%', '85%', '95%', 2, 'The Soviet bloc accounted for 85% of Cuba''s trading partners. The collapse of the USSR in 1991 led to a 40% decline in Cuba''s economy, triggering the Special Period.', 304);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-305', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The Torricelli Act restricting trade with Cuba was passed in:', '1989', '1992', '1996', '2000', 1, 'The Torricelli Act was passed in 1992, followed by the Helms-Burton Act in 1996. Both aimed to tighten the US trade embargo against Cuba during the Special Period.', 305);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-306', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Cuba''s 1961 literacy campaign raised literacy rates to approximately:', '70%', '85%', '96%', '100%', 2, 'The 1961 literacy campaign raised literacy from 40% to a reported 96%, the highest in Latin America and one of the highest in the world at the time.', 306);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-307', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The number of teachers in Cuba increased from 20,000 pre-Revolution to how many by 1963?', '30,000', '45,000', '60,000', '100,000', 2, 'The number of teachers tripled from 20,000 to 60,000 between the pre-Revolution period and 1963, though this was partially offset by the brain drain of teachers leaving Cuba (1959-1961).', 307);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-308', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The Federation of Cuban Women was established in:', '1953', '1959', '1960', '1965', 2, 'The Federation of Cuban Women (FMC) was established in 1960 to integrate women into the workforce and promote female literacy and gender equality. It expanded to 2.6 million members.', 308);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-309', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Women''s employment in Cuba rose from 13% in 1958 to what percentage by 2008?', '25%', '33%', '44%', '55%', 2, 'Women''s employment rose from 13% (1958) to 44% (2008). Women also held 43% of parliamentary seats by 2008, though cultural resistance (machismo) limited the real impact of gender policies.', 309);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-310', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The 1975 Family Code in Cuba aimed to:', 'Restrict women''s access to education', 'Dismantle patriarchal family structures and mandate shared domestic labour', 'Encourage higher birth rates', 'Nationalise childcare entirely', 1, 'The 1975 Family Code aimed to create egalitarian family law, requiring men to do half the chores, providing maternity cover, abortions, and day-care, and simplifying divorce. However, it was largely ignored in practice.', 310);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-311', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Which of the following was NOT a guerrilla tactic used by Castro in the Sierra Maestra?', 'Hit-and-run attacks', 'Small autonomous groups', 'Large-scale frontal assaults on cities', 'Retreating when attacked', 2, 'Castro''s guerrillas used classic guerrilla tactics: retreat when attacked, hit-and-run attacks, small autonomous groups, and mobile forces with peasant support. They avoided large-scale frontal assaults, which was Batista''s failing strategy.', 311);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-312', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Radio Rebelde was significant because it:', 'Was used by Batista to spread propaganda', 'Became the most popular radio station in Cuba, spreading Castro''s message', 'Was funded by the CIA', 'Broadcast exclusively in English for international audiences', 1, 'Radio Rebelde became the most popular radio station in Cuba, spreading revolutionary propaganda and Castro''s message from the Sierra Maestra. Along with the newspaper El Cubano Libre, it was key to building support.', 312);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-313', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'The Escambray Rebellion was primarily composed of:', 'Communist guerrillas', 'Wealthier peasants, middle class, and Batista loyalists opposing Castro', 'Foreign mercenaries', 'University students', 1, 'The Escambray rebels were mainly wealthier peasants, middle class, and local farmers who opposed expropriation and reorganisation, plus Batista loyalists. They had no outstanding leaders, were outnumbered, and lacked popular support.', 313);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-314', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Castro''s period of consolidation is generally considered to be:', '1953-1956', '1956-1959', '1959-1965', '1965-1975', 2, 'The consolidation period was 1959-1965 — from Castro taking power to when all active external and internal opposition had been eliminated. His key acts were 1959-1961, and foreign opposition died down by 1965.', 314);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-315', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Which historian described Cuba''s education policies as achieving egalitarian goals more than anywhere else?', 'Fischer', 'Perez', 'Tanay', 'Wolf', 1, 'Perez stated: "Nowhere was the quest for an egalitarian society more fully attained than in the area of education." This reflects the widely acknowledged success of Castro''s education reforms.', 315);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-316', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'What was a key pragmatic economic response during Cuba''s Special Period?', 'Increased trade with the USSR', 'Dollarisation of the economy and inviting foreign firms', 'Nationalisation of all remaining private businesses', 'Military expansion', 1, 'During the Special Period, Cuba pursued pragmatic policies including dollarisation, encouraging private enterprise, and inviting foreign firms (1995). However, under George W. Bush''s pressure, Cuba moved against dollarisation by 2004.', 316);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-317', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'Cuba''s population grew from 5.8 million in 1953 to approximately how many by 1970?', '6.5 million', '7.5 million', '8.5 million', '10 million', 2, 'Cuba''s population increased from 5.8 million (1953) to 8.5 million (1970). Birth rates surged from 27/1000 (1958) to 37/1000 (1962), though this increase did not sustain long-term.', 317);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-318', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'What was the Pact of Caracas (1958)?', 'A military alliance between Cuba and Venezuela', 'An agreement by all opposition groups to end Batista''s regime and restore democracy', 'A trade deal between Cuba and the Soviet Union', 'A peace treaty ending the Cuban Revolution', 1, 'The Pact of Caracas (1958) saw all opposition groups agree to end the Batista regime and restore democracy. Castro, however, did not follow through on the democratic restoration promise after taking power.', 318);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-319', '6. Cuba (Castro)', 'SL/HL', 'P2-AUTH', 'By the mid-1990s, how many dissident groups had emerged in Cuba?', 'Fewer than 10', 'Over 50', 'Over 200', 'Over 500', 1, 'By the mid-1990s, over 50 dissident groups had emerged — the first time since 1965 with such significant dissidence. However, Castro''s regime quelled this opposition with force, arresting 100 members of Concilio Cubano in 1996.', 319);

-- ── A4. New Written Questions ────────────────────────────────────────────

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-130', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the role of guerrilla warfare in Castro''s rise to power.', '• Band 5 (13-15): Detailed analysis of guerrilla tactics (retreat when attacked, hit-and-run, small autonomous groups, peasant support) and their effectiveness against Batista''s conventional forces. Must discuss specific engagements (La Plata, El Uvero, Santa Clara) with evidence. Should also evaluate the role of propaganda (Radio Rebelde, NYT interview) and political factors alongside military ones. The rebel army never exceeded ~2,000 men yet defeated a much larger force.
• Band 3 (7-9): Some relevant knowledge of guerrilla tactics but limited specific evidence or evaluation of relative importance.
• Band 1 (1-3): Vague description with no specific military engagements or analysis.', 130);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-131', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent was Castro''s consolidation of power (1959-65) reliant on the use of force?', '• Band 5 (13-15): Balanced evaluation weighing use of force (trials/executions, crushing Escambray Rebellion, suppressing Matos/Morgan) against other methods: legal methods (nationalisation, land reform), charismatic leadership (personal appeal, eating same rations as troops), propaganda (Radio Rebelde, highlighting Bay of Pigs as US interference), and ideological flexibility. Must consider that consolidation was complete by 1965.
• Band 3 (7-9): Some analysis of force and other methods but may lack balance or specific evidence.
• Band 1 (1-3): Simple assertion about force with no supporting evidence.', 131);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-132', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the successes and limitations of Castro''s social policies in education and healthcare.', '• Band 5 (13-15): Detailed evaluation with specific statistics. Education: teachers 20,000→60,000, literacy 40%→96%, primary enrollment 800,000→3.3M, secondary schools 80→1,900. Perez: "nowhere was the quest for an egalitarian society more fully attained than in education." Healthcare: free for all, 1,100 doctors/year, polio eliminated, malaria-free. BUT: brain drain of teachers 1959-61, indoctrination concerns, medicine shortages due to embargo, healthcare gains did not survive Special Period. Must reach a balanced judgement.
• Band 3 (7-9): Some statistics but limited evaluation of successes vs. limitations.
• Band 1 (1-3): General claims about education/healthcare without evidence.', 132);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-133', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent did the Special Period (1991-96) threaten Castro''s hold on power?', '• Band 5 (13-15): Detailed analysis of the crisis: USSR collapse, 85% of trade lost, economy fell 40%, severe hardship (no fuel, power shortages), Torricelli Act (1992), Helms-Burton Act (1996). Response: pragmatic policies (dollarisation, private enterprise, foreign firms), ideological emphasis, US as bogeyman uniting Cubans. 50+ dissident groups emerged but were suppressed (Concilio Cubano arrests 1996). Must evaluate whether the regime was genuinely threatened or adapted effectively.
• Band 3 (7-9): Some knowledge of the Special Period but limited analysis of the threat to power.
• Band 1 (1-3): Vague awareness of economic difficulties without specific evidence.', 133);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-134', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the impact of Castro''s policies on women in Cuba.', '• Band 5 (13-15): Detailed analysis of policies and their real impact. Achievements: Federation of Cuban Women (1960, 2.6M members), employment 13%→44%, 43% of parliament (2008), literacy campaign mobilised 100,000 women (56% of newly literate were women), women dominate higher education (70% med school 2008). 1975 Family Code mandated equality. 1968 nationalisation: 90% of new administrators were women. BUT: Family Code largely ignored (women did 75% of domestic labour in 1990s), 76% of women who entered labour force in 1969 dropped out within a year, cultural machismo persisted, Special Period pushed women into sex work. Tanay: "good intentions, but fundamentally useless."
• Band 3 (7-9): Some knowledge of policies but limited analysis of gap between policy and reality.
• Band 1 (1-3): Vague claims about gender equality without evidence.', 134);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-135', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare and contrast the emergence of Castro and one other authoritarian leader.', '• Band 5 (13-15): Systematic comparison of conditions (economic, political, social) and methods (use of force, propaganda, legal, charismatic) for Castro and another leader (e.g., Hitler, Mao). Castro: Batista''s corruption, US economic dominance, guerrilla warfare, Moncada/Sierra Maestra, propaganda (Radio Rebelde). Must show genuine comparison with similarities and differences, not two separate narratives.
• Band 3 (7-9): Some comparison but may be largely descriptive or two separate accounts.
• Band 1 (1-3): Vague comparison with no specific evidence from either case.', 135);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-136', '6. Cuba (Castro)', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent did Castro achieve authoritarian control over Cuba?', '• Band 5 (13-15): Evaluative argument assessing the degree of control. Evidence of control: one-party state, elimination of opposition by 1965, censorship, CDR surveillance, control of education as propaganda. Evidence of limitations: Special Period dissidence (50+ groups), brain drain/emigration, economic failures, cultural resistance to social policies (machismo, Family Code ignored), reliance on USSR. Must define what "authoritarian control" means and reach a clear judgement.
• Band 3 (7-9): Some analysis but may overstate or understate degree of control.
• Band 1 (1-3): Simple assertion without evidence or criteria for judgement.', 136);


