INSERT OR IGNORE INTO history_checklist_sections (id, title, color, unit, sort_order) VALUES ('hist-p2-war-cl-7', '7. WWI: Detailed Causes, Course & Consequences', '#C4A36A', 'P2-WAR', 107);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can explain the ANIMAL framework for WWI causes (Alliances, Nationalism, Imperialism, Militarism, Assassination, List of events)', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can describe the Concert of Europe and why it failed', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can analyse Balkan tensions (pan-Slavism, Bosnia-Herzegovina annexation, Serbian nationalism)', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can discuss the Moroccan Crises (1905, 1911) and their significance', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can explain Weltpolitik and the naval arms race (Dreadnoughts)', 5);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can analyse the July Crisis and the role of the ''blank cheque''', 6);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can describe key Western Front battles with casualty figures (Verdun, Somme)', 7);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can explain the Eastern Front and the Brusilov Offensive', 8);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can discuss US entry (submarine warfare, Zimmerman Telegram)', 9);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can analyse the Ludendorff Offensive and why it failed', 10);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can explain naval warfare (Jutland, U-boats, convoys) and air warfare', 11);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can discuss the Russian Revolution''s impact and Treaty of Brest-Litovsk', 12);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can evaluate the historiographical debate on WWI responsibility (Fischer, Fay, Winter)', 13);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p2-war-cl-7', 'I can analyse the Treaty of Versailles terms and consequences in detail', 14);

-- ── B2. New Flashcard Topic & Cards ──────────────────────────────────────
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-7', '7. WWI: Detailed Causes, Course & Consequences', '#C4A36A', 'P2-WAR', 7);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Congress of Vienna (1814-15)', 'After Napoleon''s defeat, the Congress of Vienna aimed to balance the great powers, creating stability and cracking down on republican/democratic challenges. Talleyrand prevented France from losing significant territory. Led to the Concert of Europe — an informal agreement maintaining European balance of power for most of the 19th century.', 1);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'ANIMAL Framework for WWI Causes', 'A = Alliances (Triple Alliance, Triple Entente), N = Nationalism, I = Imperialism, M = Militarism, A = Assassination of Franz Ferdinand (immediate cause), L = List of events c.1871-1914. Long-term causes did not mean war was inevitable — a crisis was still necessary to push governments into conflict.', 2);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Balkan Tensions', 'Ottoman fragmentation created smaller states (Serbia, Bulgaria), allowing Russia and Austria-Hungary to compete for influence. Russia promoted pan-Slavism. Austria-Hungary annexed Bosnia-Herzegovina in 1908 — Russia was furious but militarily unable to respond. Serbia pushed for a "Greater Serbia" uniting Balkan Slavs. Key Austro-Hungarian leaders wanted to deal with Serbia before it grew stronger.', 3);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Moroccan Crises (1905 & 1911)', '1905: France moved to control Morocco; Germany objected, threatening war. Algeciras Conference forced Germany to back down. 1911: France sent troops into Morocco; Germany demanded territory; Britain and France gave Germany portions of French Congo. Germany felt "insulted, defeated and humiliated." The crises strengthened the Anglo-French entente.', 4);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Weltpolitik', 'Kaiser Wilhelm II''s policy of extending German influence worldwide through a powerful navy and colonies. In 1896 he declared "nothing must henceforth be settled in the world without the intervention of Germany." German Foreign Minister: "we too demand our place in the sun." This threatened British and French interests.', 5);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Naval Arms Race', 'Germany challenged British naval dominance. Britain responded with Dreadnought-class battleships. 1906: Britain had 1 Dreadnought, Germany 0. By 1914: Britain had 29, Germany 17. Germany felt it was losing the arms race, and the gap kept growing — making them believe if war was inevitable, it was better now than later.', 6);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Alliance System Detail', 'Triple Alliance: Germany + Austria-Hungary (Dual Alliance, formed due to German fears of Russia) + Italy (joined 1882). Defensive alliance with autonomy. Triple Entente: Russia + France (1894, fear of Germany) + Britain (Entente Cordiale 1904, Anglo-Russian Convention 1907). Geographically, Germany was nearly surrounded. "The idea that the alliance system led to war by chain reaction is only superficially compelling" — in 1914, each power joined on its own terms.', 7);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Military Plans', 'Schlieffen Plan: Attack France through Belgium, capture Paris in 6 weeks, then turn east against Russia (expected 8-week mobilisation). Russia: emphasised early mobilisation. France: Plan XVII — concentrated attack through Lorraine. Austria-Hungary: multi-front concern (Russia, Serbia, Romania), weak technologically. Britain: small standing army, rapid deployment to France, Royal Navy blockade. All plans assumed a short war.', 8);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'July Crisis & Blank Cheque', 'After the assassination of Archduke Franz Ferdinand (28 June 1914), Austria-Hungary delivered a deliberately harsh ultimatum to Serbia (48 hours). Germany offered a "blank cheque" — unconditional support (6 July). Serbia accepted all demands except those violating its constitution. Germany refused Britain''s proposed conference (26 July). German chancellor only backtracked on 29 July when British and Russian intentions became clear.', 9);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Schlieffen Plan Failure', 'Germans made rapid progress through Belgium and Luxembourg, but: (1) British forces slowed them at Mons, (2) railway damage left railheads 135km behind front lines, (3) gaps in German lines were exploited by the enemy. Germans were stopped at the Battle of the Marne (6-9 September 1914). Both sides entrenched, leading to the "Race to the Sea" — trench lines from Switzerland to the English Channel.', 10);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Trench Warfare Technology', 'Defenders had enormous advantage. Machine guns: 500 rounds/minute in fixed positions (later evolved into mobile, single-man guns). Britain massively outproduced Germany: 1914 — Britain 300, Germany 500; 1918 — Britain 120,900, Germany 13,000. Attack methods: preliminary artillery bombardment, creeping barrage, mines, poison gas, tanks (from 1916, mainly British/French, 5,000+ by 1918).', 11);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Battle of Verdun (Feb-Dec 1916)', 'German attack on French fortresses aiming to divert forces through continuous bombardment. A massive battle of attrition: 542,000 French casualties, 430,000 German dead. After 10 months, France held Verdun and Germans gained only 8 km of territory.', 12);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Battle of the Somme (Jul-Nov 1916)', 'British aimed to break the stalemate and draw Germans from Verdun. Preliminary bombardment and early tank use failed to weaken German trenches. 54,740 casualties (half dead) on the first day. Continued July-November despite losses: 420,000 British, 200,000 French, 500,000 German. Negligible territorial gains.', 13);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Brusilov Offensive (June-Sep 1916)', 'Russian offensive targeting Austro-Hungarians in Ukraine, partly to relieve Italians. Started well — 96 km gained in June. Stalled due to insufficient supplies; Germans moved troops from Verdun; ended September 1916. Cost 1 million Russian men and created discontent in Russia. But it totally crippled Austro-Hungarian military, which needed significant German support afterwards.', 14);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'US Entry into WWI (April 1917)', 'USA joined Allies due to: (1) German submarine warfare targeting US vessels, (2) Zimmerman Telegram encouraging Mexico to invade the US (massive fail — instead of keeping US focused on Mexico, it brought US into WWI). By March 1918, 250,000 US troops were arriving monthly in Europe, which devastated German morale.', 15);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Treaty of Brest-Litovsk (1918)', 'Bolsheviks ended Russia''s war with Central Powers. Russia lost: 2.6 million km2 of territory (Poland, Lithuania, Ukraine, Baltics), 75% of iron ore, 90% of coal, 50% of industry, 55 million people, and half its agricultural land. Most spoils went to Germany, freeing them to focus on the Western Front.', 16);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Ludendorff Offensive (March-June 1918)', 'Germany''s massive final offensive using: hurricane barrages (short, intensive bombardments), and infiltration tactics — smaller stormtrooper detachments attacking weak points for surprise and speed. Initially gained 65 km in the first week. Stalled due to lack of reserves and supplies. Allied tanks and aircraft forced retreat at Second Battle of the Marne (July-August 1918). Retreat became irreversible.', 17);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'War at Sea', 'British naval blockade confined German navy to ports, devastating supplies. Battle of Jutland (1916): British lost 14 ships, Germany 11 — inconclusive but blockade continued. Germany turned to U-boat submarine warfare: 748,000 tons sunk in 1915, 500,000 tons in April 1917 alone. Sinking of Lusitania angered US. British used convoys, Q-ships (disguised military vessels), and depth charges against submarines.', 18);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'War in the Air', 'Initially used for reconnaissance (Battle of Tannenberg, August 1914). Fighter aircraft developed with machine guns — Germans had superior technology but Allies had far more aircraft. Zeppelins used for bombing (easy targets). Strategic bombing possible but not decisive. Aircraft began supporting ground troops (Cambrai, Ludendorff Offensive).', 19);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Spanish Influenza & Disease', 'Soldiers in trenches faced malaria, typhoid from terrible sanitation. Spanish influenza (January 1918 - December 1920) killed ~120 million people (6% of world population). 500,000 German troops were too ill to fight, significantly impacting the Ludendorff Offensive and the war''s final phase.', 20);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Collapse of Central Powers (1918)', 'Bulgaria surrendered 29 September, Ottomans 30 October, Austria-Hungary 3 November 1918. They could not sustain conflict: lacked reserves, home situations deteriorated, governments lost appetite for war. A mutiny in the German navy preceded the Armistice (11 November 1918).', 21);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'WWI Responsibility Debate', 'Sidney Bradshaw Fay (US): proposed collective responsibility, opposing sole German blame from Treaty of Versailles. Fritz Fischer: argued Germany deliberately planned war for annexation and colonial expansion. Gerhard Ritter: disagreed with Fischer, noting annexation plans were made when war was underway. JM Winter: "If Germany may be said to have brought about WWI, it did so as part of a political community which collectively let the peace of Europe slip through its fingers." Consensus: collective responsibility with emphasis on German actions.', 22);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Middle Eastern Theatre', 'Allies aimed to knock Ottomans out of war, boost morale, open Russian supply routes. Gallipoli (ANZAC troops): amphibious assault, highly unsuccessful, 45,000+ dead. Mesopotamia: British captured Basra (1914) for oil, then Baghdad (1917). British encouraged Arab Revolt against Ottomans, promising independence (not honoured). October 1918: Ottoman surrender.', 23);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Poison Gas in WWI', 'Germans used poison gas at Second Battle of Ypres, gaining 7 km. Allies had 69,000 casualties, Germans 38,000. But gas caused less than 1% of war fatalities — its significance was more psychological. Both sides eventually deployed gas, but effective countermeasures (gas masks) limited its tactical impact.', 24);

INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'Eastern Front Overview', 'Russia had faster mobilisation than expected. Russia drove deep into Galicia (Austria-Hungary) but less success against Germany. At Battle of Tannenberg (29 August 1914), Germans encircled and defeated Russians — their closest approach to threatening Germany. After that, fighting remained at the Eastern Front without deep penetration.', 25);

-- ── B3. New MCQ Questions ────────────────────────────────────────────────

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-320', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'The Concert of Europe originated from:', 'The Treaty of Versailles (1919)', 'The Congress of Vienna (1814-15)', 'The Berlin Conference (1884-85)', 'The Hague Conventions (1899)', 1, 'The Concert of Europe was an informal system of maintaining European balance of power that emerged from the Congress of Vienna (1814-15), held after Napoleon''s defeat.', 320);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-321', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Austria-Hungary annexed Bosnia-Herzegovina in:', '1878', '1903', '1908', '1914', 2, 'Austria-Hungary annexed Bosnia-Herzegovina in 1908. Russia was unable to respond militarily but was furious, and determined to prevent further Austrian expansion in the Balkans.', 321);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-322', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Weltpolitik was the foreign policy of:', 'Tsar Nicholas II', 'Kaiser Wilhelm II', 'King Edward VII', 'Emperor Franz Joseph', 1, 'Weltpolitik was Kaiser Wilhelm II''s policy of extending German influence worldwide through a powerful navy and colonial expansion. He declared "nothing must henceforth be settled in the world without the intervention of Germany."', 322);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-323', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'By 1914, how many Dreadnought-class battleships did Britain have compared to Germany?', 'Britain 17, Germany 29', 'Britain 29, Germany 17', 'Britain 20, Germany 20', 'Britain 10, Germany 25', 1, 'By 1914 Britain had 29 Dreadnoughts to Germany''s 17. In 1906, Britain had 1 and Germany had none. The naval arms race was a key source of Anglo-German tension.', 323);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-324', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Germany''s "blank cheque" to Austria-Hungary was issued on:', '28 June 1914', '6 July 1914', '26 July 1914', '1 August 1914', 1, 'On 6 July 1914, Germany offered Austria-Hungary unconditional support (the "blank cheque") against Serbia. This emboldened Austria-Hungary to issue its deliberately harsh ultimatum.', 324);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-325', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'The Germans were stopped at which battle in September 1914, ending the Schlieffen Plan?', 'Battle of Tannenberg', 'Battle of the Marne', 'Battle of Verdun', 'Battle of Ypres', 1, 'The Germans were stopped at the Battle of the Marne (6-9 September 1914). Both sides then entrenched, leading to the "Race to the Sea" and the trench warfare stalemate.', 325);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-326', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'French casualties at Verdun were approximately:', '100,000', '250,000', '542,000', '800,000', 2, 'The Battle of Verdun (February-December 1916) cost approximately 542,000 French casualties and 430,000 German dead. After 10 months, France held Verdun and Germany gained only 8 km.', 326);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-327', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'The Brusilov Offensive (1916) gained how much territory in its first month?', '8 km', '25 km', '65 km', '96 km', 3, 'The Brusilov Offensive gained 96 km in its first month (June 1916) against Austria-Hungary. It stalled by July due to insufficient supplies, but it totally crippled the Austro-Hungarian military.', 327);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-328', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'The Zimmerman Telegram encouraged which country to invade the United States?', 'Canada', 'Cuba', 'Mexico', 'Japan', 2, 'The Zimmerman Telegram (1917) encouraged Mexico to invade the US. This backfired catastrophically for Germany — instead of keeping the US focused on a war with Mexico, it helped bring the US into WWI.', 328);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-329', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Under the Treaty of Brest-Litovsk, Russia lost what percentage of its coal?', '25%', '50%', '75%', '90%', 3, 'Russia lost 90% of its coal, 75% of its iron ore, 50% of its industry, 55 million people, half its agricultural land, and 2.6 million km2 of territory under the Treaty of Brest-Litovsk.', 329);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-330', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'The Ludendorff Offensive used which new tactic?', 'Trench mining', 'Infiltration tactics with stormtroopers', 'Naval bombardment of trenches', 'Aerial carpet bombing', 1, 'The Ludendorff Offensive used infiltration tactics — smaller stormtrooper detachments attacking weak points for surprise and speed. Combined with hurricane barrages, they initially gained 65 km in the first week before stalling.', 330);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-331', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'At the Battle of Jutland (1916), who lost more ships?', 'Germany (14 ships lost)', 'Britain (14 ships lost)', 'They lost an equal number', 'Neither side lost any ships', 1, 'Britain lost 14 ships at Jutland compared to Germany''s 11. However, the battle was strategically inconclusive — the British maintained their blockade and the German navy remained largely confined to port.', 331);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-332', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Fritz Fischer''s interpretation of WWI was that:', 'All powers shared equal responsibility', 'Germany deliberately planned and sought the war', 'Britain was primarily responsible', 'The war was an accident caused by miscommunication', 1, 'Fritz Fischer argued Germany deliberately sought war for annexation and colonial expansion. Gerhard Ritter disagreed, noting annexation plans were made when war was underway. The consensus settled on collective responsibility with emphasis on German actions.', 332);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-333', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Spanish Influenza (1918-1920) killed approximately:', '10 million people', '50 million people', '120 million people', '200 million people', 2, 'Spanish Influenza killed approximately 120 million people (6% of the world population). In the war, 500,000 German troops were too ill to fight, significantly impacting the final phase of the conflict.', 333);

INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-334', '2. World War I (1914-1918)', 'SL/HL', 'P2-WAR', 'Poison gas in WWI accounted for what proportion of total fatalities?', 'Less than 1%', 'About 5%', 'About 15%', 'About 25%', 0, 'Poison gas caused less than 1% of total war fatalities. Its significance was primarily psychological rather than strategic. Both sides deployed gas but effective countermeasures (gas masks) limited its tactical impact.', 334);

-- ── B4. New Written Questions ────────────────────────────────────────────

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-140', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent was Germany responsible for the outbreak of World War I?', '• Band 5 (13-15): Evaluative argument engaging with the historiographical debate. Fischer: Germany deliberately sought war for expansion. Fay: collective responsibility. Winter: "Germany brought about WWI as part of a political community." Evidence for German responsibility: blank cheque, Weltpolitik, naval arms race, refusal of British conference proposal, Schlieffen Plan requiring rapid action. Evidence against sole responsibility: alliance system dynamics, Russian mobilisation, Austro-Hungarian aggression, Balkan nationalism, imperial rivalries. Must reach a substantiated judgement.
• Band 3 (7-9): Some engagement with historiography but limited evidence or imbalanced argument.
• Band 1 (1-3): Simple assertion about blame without supporting evidence.', 140);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-141', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent did the long-term causes of WWI make conflict inevitable by 1914?', '• Band 5 (13-15): Evaluative analysis of ANIMAL framework causes. Alliances: created encirclement fears, but terms were vague and did not compel action. Nationalism: glorified military strength, assimilated Social Darwinism, created atmosphere where war was an "opportunity." Imperialism: new arena for conflict (Moroccan Crises), but most imperial disputes resolved diplomatically. Militarism: arms race, Dreadnoughts, standing armies growing, war plans (Schlieffen) requiring rapid action. Must argue whether these made war inevitable or whether a crisis was still necessary. Short-term causes and miscalculations also needed to trigger actual war.
• Band 3 (7-9): Some discussion of causes but limited evaluation of inevitability.
• Band 1 (1-3): Simple listing of causes without analysis.', 141);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-142', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Evaluate the significance of technology in determining the outcome of World War I.', '• Band 5 (13-15): Detailed analysis of specific technologies with evaluation of their impact. Machine guns: created stalemate (500 rpm), Britain massively outproduced Germany (120,900 vs 13,000 by 1918). Tanks: from 1916, initially basic but by 1918 5,000+ used effectively. Poison gas: less than 1% of fatalities, mainly psychological. Aircraft: reconnaissance then combat, supported ground troops. Submarines: U-boats sank 748,000 tons (1915), nearly starved Britain. Railways: critical for mobilisation and logistics. Must evaluate whether technology determined the outcome or whether other factors (US entry, blockade, leadership, morale) were more significant.
• Band 3 (7-9): Some relevant examples but limited evaluation of relative significance.
• Band 1 (1-3): Vague listing of technologies without analysis.', 142);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-143', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'How significant was the management of the war in determining its outcome?', '• Band 5 (13-15): Analysis of military leadership and strategic decisions. Failed strategies: Schlieffen Plan (logistics failure, railheads 135km behind), Verdun (10 months for 8km), Somme (54,740 casualties day 1). Successful adaptations: Allied combined arms (tanks + aircraft), convoy system against U-boats, Brusilov Offensive tactics. Ludendorff Offensive used innovative infiltration tactics but failed due to overextension. All plans assumed short war — if leaders knew the war''s length, they may have been more hesitant. Must evaluate management against other factors: resources, US entry, home front, disease (Spanish flu).
• Band 3 (7-9): Some discussion of military decisions but limited evaluation of significance.
• Band 1 (1-3): Vague assertions about leadership without specific examples.', 143);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-144', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Did the impact of WWI make future European conflict more or less likely?', '• Band 5 (13-15): Evaluative argument considering multiple consequences. More likely: Treaty of Versailles resentment (war guilt, reparations, territorial losses), creation of many new democratic states prone to instability, economic disruption, rise of extremist ideologies (communism, fascism), failure of League of Nations, unresolved ethnic tensions. Less likely: horror of war should have deterred conflict, League of Nations created mechanisms for peaceful resolution, democratic spread, disarmament efforts. Must reach a clear judgement with specific evidence linking WWI outcomes to subsequent developments (Weimar instability, rise of Hitler, WWII).
• Band 3 (7-9): Some analysis of consequences but limited evaluation of likelihood of future conflict.
• Band 1 (1-3): Simple assertion without evidence.', 144);
